// Extract data from Supabase result
const data = $input.first().json;

// Helper function to safely get array length
const getCount = (arr) => Array.isArray(arr) ? arr.length : 0;

// Helper function to count by property value
const countBy = (arr, prop, value) => {
  if (!Array.isArray(arr)) return 0;
  return arr.filter(item => item && item[prop] === value).length;
};

// Helper function to group by property
const groupBy = (arr, prop) => {
  if (!Array.isArray(arr)) return {};
  return arr.reduce((acc, item) => {
    if (item && item[prop]) {
      const key = item[prop];
      acc[key] = (acc[key] || 0) + 1;
    }
    return acc;
  }, {});
};

// Extract arrays
const doctors = data.doctors || [];
const nurses = data.nurses || [];
const patients = data.patients || [];
const beds = data.beds || [];
const appointments = data.appointments || [];
const riskPatients = data.risk_patients || [];

// Calculate statistics
const stats = {
  doctors: {
    total: getCount(doctors),
    onDuty: countBy(doctors, 'status', 'On Duty'),
    offDuty: countBy(doctors, 'status', 'Off Duty'),
    byDepartment: groupBy(doctors, 'department'),
    bySpecialty: groupBy(doctors, 'specialty')
  },
  nurses: {
    total: getCount(nurses),
    active: countBy(nurses, 'status', 'Active'),
    onBreak: countBy(nurses, 'status', 'On Break'),
    byDepartment: groupBy(nurses, 'department'),
    byShift: groupBy(nurses, 'shift')
  },
  patients: {
    total: getCount(patients),
    inTreatment: countBy(patients, 'status', 'In Treatment'),
    admitted: countBy(patients, 'status', 'Admitted'),
    discharged: countBy(patients, 'status', 'Discharged'),
    byRiskLevel: groupBy(patients, 'risk_level'),
    byDepartment: groupBy(patients, 'department')
  },
  beds: {
    total: getCount(beds),
    available: countBy(beds, 'status', 'Available'),
    occupied: countBy(beds, 'status', 'Occupied'),
    maintenance: countBy(beds, 'status', 'Maintenance'),
    byType: groupBy(beds, 'type'),
    byDepartment: groupBy(beds, 'department'),
    occupancyRate: getCount(beds) > 0 ? 
      ((countBy(beds, 'status', 'Occupied') / getCount(beds)) * 100).toFixed(2) : 0
  },
  appointments: {
    total: getCount(appointments),
    confirmed: countBy(appointments, 'status', 'Confirmed'),
    pending: countBy(appointments, 'status', 'Pending'),
    completed: countBy(appointments, 'status', 'Completed'),
    cancelled: countBy(appointments, 'status', 'Cancelled'),
    byDepartment: groupBy(appointments, 'department')
  },
  riskPatients: {
    total: getCount(riskPatients),
    byRiskLevel: groupBy(riskPatients, 'risklevel')
  }
};

// Return formatted dashboard data
return [{
  json: {
    summary: stats,
    data: {
      doctors,
      nurses,
      patients,
      beds,
      appointments,
      riskPatients
    },
    timestamp: new Date().toISOString(),
    recordCounts: {
      doctors: getCount(doctors),
      nurses: getCount(nurses),
      patients: getCount(patients),
      beds: getCount(beds),
      appointments: getCount(appointments),
      riskPatients: getCount(riskPatients)
    }
  }
}];

