return $input.all().map(item => {
    const tableName = item.json.table_name;
    let identifierField = '';

    switch (tableName) {
        case 'patients':
            identifierField = 'patient_id';
            break;
        case 'risk_patients':
            identifierField = 'sessionid';
            break;
        case 'nurses':
            identifierField = 'nurse_id';
            break;
        case 'doctors':
            identifierField = 'doctor_id';
            break;
        case 'beds':
            identifierField = 'bed_id';
            break;
        case 'appointments':
            identifierField = 'session_id';
            break;
        default:
            throw new Error(`Unknown table name: ${tableName}`);
    }

    return {
        json: {
            ...item.json,
            identifier_field: identifierField
        }
    };
});
